import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface DigitalIntegration {
  code: string;
  requirement: string;
  description: string;
}

export interface Step {
  stepName: string;
  teacherAction: string;
  output: string;
}

export interface Activity {
  name: string;
  objective: string;
  content: string;
  product: string;
  steps: Step[];
  digitalIntegration?: DigitalIntegration;
}

export interface Objectives {
  knowledge: string[];
  competency: string[];
  quality: string[];
}

export interface LessonPlan {
  topic: string;
  subject: string;
  grade: string;
  duration: string;
  objectives: Objectives;
  materials: string[];
  activities: Activity[];
}

export interface WorksheetItem {
  type: 'fill' | 'essay';
  question: string;
}

export interface Worksheet {
  title: string;
  description: string;
  content: WorksheetItem[];
}

export interface Slide {
  type: string;
  title: string;
  points: string[];
}

export interface AssessmentQuestion {
  level: string;
  question: string;
  options: string[];
  answer: string;
  explanation: string;
}

export interface DigitalMapping {
  activity: string;
  competencyCode: string;
  competency: string;
  tool: string;
  action: string;
  evidence: string;
}

export interface DigitalPack {
  summary: string;
  mapping: DigitalMapping[];
}

export interface FormData {
  grade: string;
  subject: string;
  topic: string;
  duration: string;
  template: string;
  classLevel: string;
  integrationMode: string;
  originalText: string;
  products: string[];
  selectedFramework: string;
}

export interface ResultData {
  lessonPlan: LessonPlan;
  assessment: AssessmentQuestion[];
  worksheets: Worksheet[];
  slides: Slide[];
  digitalPack: DigitalPack;
  mode: 'creation' | 'integration';
}

