                ]
            },
            materials: [
                "Sách giáo khoa Toán 10.",
                "Máy chiếu, phần mềm GeoGebra.",
                "Phiếu học tập số 1 & 2."
            ],
            activities: [
                {
                    name: "Hoạt động 1: Mở đầu (Khởi động)",
                    objective: "Tạo tình huống có vấn đề từ thực tiễn để dẫn dắt vào bài mới.",
                    content: "GV chiếu hình ảnh một trạm phát sóng Rađa quét tín hiệu trong phạm vi bán kính R=50km.",
