                        { stepName: "Thực hiện", teacherAction: "HS làm việc cá nhân, thiết lập biểu thức.", output: "HS viết ra giấy nháp." },
                        { stepName: "Báo cáo", teacherAction: "GV mời 1 HS đứng tại chỗ trình bày.", output: "HS trình bày." },
                        { stepName: "Kết luận", teacherAction: "GV dẫn dắt vào bài định nghĩa đường tròn.", output: "HS ghi tựa bài." }
                    ],
                    digitalIntegration: {
                        code: "1.1.TC1a", 
                        requirement: pickComp("1.1.TC1a").requirement,
                        description: "HS xác định từ khoá 'phương trình đường tròn' để chuẩn bị tìm kiếm thêm."
                    }
                },
                {
                    name: "Hoạt động 2: Hình thành kiến thức mới",
