                    content: "HS làm việc theo cặp đôi. Dựa vào định nghĩa đường tròn, thiết lập hệ thức.",
                    product: "Công thức: (x-a)^2 + (y-b)^2 = R^2.",
                    steps: [
                        { stepName: "Chuyển giao", teacherAction: "GV chia lớp thành các cặp đôi, phát phiếu.", output: "HS nhận phiếu." },
                        { stepName: "Thực hiện", teacherAction: "HS thảo luận cặp đôi. GV quan sát.", output: "HS viết công thức." },
                        { stepName: "Báo cáo", teacherAction: "GV mời đại diện 1 nhóm lên bảng.", output: "Kết quả trên bảng." },
