                        {auditResult && (
                            <div className="bg-slate-800 p-3 rounded border border-green-500/30 text-xs text-green-400 animate-fade-in">
                                <p className="font-bold">Điểm sư phạm: {auditResult.score}/100</p>
                                <p className="opacity-80">Cấu trúc hợp lý, mục tiêu rõ ràng.</p>
                            </div>
                        )}
                        <div className="flex flex-wrap gap-2 pt-4 border-t border-white/10">
                            <div onClick={handleExportWord} className="flex h-9 items-center gap-2 rounded-full bg-slate-800 px-4 cursor-pointer hover:bg-slate-700 transition-colors border border-gold-accent/20 w-full justify-center">
                                <FileIcon size={14} className="text-gold-accent" />
                                <p className="text-white text-xs font-semibold">Xuất Word (5512)</p>
                            </div>
                        </div>
                    </>
                )}

                <div className="flex items-center gap-3 px-3 py-2 text-slate-400 hover:text-white cursor-pointer transition-colors mt-2 border-t border-white/5 pt-4">
                    <div className="bg-slate-800 p-2 rounded-full"><User size={16} /></div>
                    <div>
                        <p className="text-xs font-bold text-white">GV. Nguyễn Văn A</p>
                        <p className="text-[10px]">Trường THPT Trần Phú</p>
                    </div>
                </div>
            </div>
        </div>
      </aside>

      {/* MAIN CONTENT AREA */}
      <main className="flex-1 flex flex-col h-full relative overflow-hidden bg-premium">
        {/* Background Decor */}
        <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-gold-accent/5 rounded-full blur-[120px] -z-10 translate-x-1/2 -translate-y-1/2"></div>
        <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-gold-primary/5 rounded-full blur-[100px] -z-10 -translate-x-1/2 translate-y-1/2"></div>

        {/* Top Bar (Tabs) */}
        {currentMode === 'result' && (
            <header className="w-full py-6 px-10 flex items-center justify-between z-10">
                <div className="flex bg-white p-1 rounded-full border border-gold-accent/20 shadow-sm">
                    {[
                        {id: 0, label: 'Kế hoạch bài dạy (5512)'},
                        {id: 1, label: 'Tích hợp NL Số'},
                        {id: 2, label: 'Phiếu học tập'},
                        {id: 3, label: 'Dàn ý Slide'}
                    ].map(tab => (
                        <button 
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            className={`flex items-center px-6 py-2 rounded-full text-sm font-bold transition-all ${activeTab === tab.id ? 'bg-gold-accent text-white shadow-md' : 'text-slate-500 hover:text-gold-dark'}`}
                        >
                            {tab.label}
                        </button>
                    ))}
                </div>
                <div className="text-right hidden lg:block">
                    <p className="text-xs text-slate-400 font-medium leading-none">Trạng thái: Đã lưu</p>
                    <p className="text-[10px] text-gold-primary font-bold uppercase tracking-tighter mt-1">Secured by TD-AI</p>
                </div>
            </header>
        )}

        {/* Content Body */}
        <div className="flex-1 overflow-y-auto px-10 pb-20 scrollbar-thin scrollbar-thumb-gold-accent/20 hover:scrollbar-thumb-gold-accent/40">
            {currentMode === 'home' && (
                <div className="flex flex-col items-center justify-center h-full text-center">
                    <div className="inline-flex items-center gap-3 px-6 py-2 rounded-full bg-white border border-gold-accent/20 shadow-sm mb-10">
                        <span className="flex h-2 w-2 rounded-full bg-gold-primary animate-pulse"></span>
                        <span className="text-gold-dark text-xs uppercase tracking-[0.3em] font-extrabold font-serif">Thế hệ AI Đẳng Cấp Cho Giáo Dục</span>
                    </div>
                    <h1 className="text-5xl md:text-7xl font-serif font-black tracking-tight mb-8 leading-tight text-[#2C2C2C]">
                        THẦY TRẦN ĐÔNG <br/> <span className="text-transparent bg-clip-text bg-gradient-to-r from-gold-dark to-gold-accent">AI TRAINER</span>
                    </h1>
                    <div className="flex gap-6 mt-8">
                        <button onClick={() => setCurrentMode('create_input')} className="px-8 py-4 rounded-xl bg-gradient-to-br from-gold-accent to-gold-primary text-white font-bold shadow-lg flex items-center gap-2 text-lg hover:brightness-110 active:scale-95 transition-all">
                            <Sparkles size={20}/> Bắt đầu ngay
                        </button>
                    </div>
                </div>
            )}

            {(currentMode === 'create_input' || currentMode === 'integrate_input') && (
                <div className="flex justify-center pt-10">
                    {renderInputForm()}
                </div>
            )}

            {currentMode === 'loading' && (
                <div className="flex flex-col items-center justify-center h-full">
                    <div className="w-16 h-16 border-4 border-gold-accent/30 border-t-gold-accent rounded-full animate-spin mb-6"></div>
                    <h3 className="text-xl font-bold text-gold-dark font-serif">AI đang kiến tạo bài giảng...</h3>
                </div>
            )}

            {currentMode === 'result' && resultData && (
                <div className="max-w-[1000px] mx-auto pb-10">
                    {activeTab === 0 && <LessonPlan5512View data={resultData.lessonPlan} onTransform={handleTransformMethod} onElaborate={handleSectionElaborate} />}
                    {activeTab === 1 && <DigitalCompetencyView data={resultData.digitalPack} topic={formData.topic} />}
                    {activeTab === 2 && <WorksheetView data={resultData.worksheets} />}
                    {activeTab === 3 && <SlideView data={resultData.slides} />}
                </div>
            )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  Wand2, Sparkles, Layers, Library, BarChart, 
  Minimize2, MousePointerClick, CheckCircle, File as FileIcon, User, 
  Edit3, RefreshCw, Settings, BookOpen
} from 'lucide-react';
import LessonPlan5512View from './components/LessonPlan5512View';
import WorksheetView from './components/WorksheetView';
import SlideView from './components/SlideView';
import DigitalCompetencyView from './components/DigitalCompetencyView';
import AdminDashboard from './components/AdminDashboard';
import AdminLogin from './components/AdminLogin';
import { TEMPLATES } from './constants';
import { generateDetailed5512Plan, generateMockWorksheets, generateMockSlides, generateMockDigitalPack, generateMockAssessment } from './utils/generators';
import { renderWordHTML } from './utils/export';
import { FormData, ResultData, Activity, Step } from './types';

const App = () => {
  const [currentMode, setCurrentMode] = useState<string>('home'); 
  const [formData, setFormData] = useState<FormData>({
    grade: '10', subject: 'Toán', topic: 'Phương trình đường tròn',
    duration: '2', template: 'toan_hinhhoc', classLevel: 'standard',
    integrationMode: 'inline', originalText: '', products: ['plan', 'questions'], selectedFramework: '3456_THCS' 
  });

  const [resultData, setResultData] = useState<ResultData | null>(null);
  const [activeTab, setActiveTab] = useState(0); 
  const [auditResult, setAuditResult] = useState<{score: number; issues: any[]} | null>(null);
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);

  // --- HANDLERS ---
  const handleGenerate = () => {
    setCurrentMode('loading');
    setTimeout(() => {
      const isMath = formData.subject.toLowerCase().includes('toán');
      const lessonPlan = formData.originalText && formData.originalText.length > 10
        ? generateDetailed5512Plan({...formData, topic: 'Bài học từ văn bản'}, false) // Fallback or parsing logic would go here
        : generateDetailed5512Plan(formData, isMath);

      setResultData({
        lessonPlan: lessonPlan,
        assessment: generateMockAssessment(formData, isMath),
        worksheets: generateMockWorksheets(formData, isMath),
        slides: generateMockSlides(formData),
        digitalPack: generateMockDigitalPack(formData),
        mode: formData.originalText ? 'integration' : 'creation'
      });
      setCurrentMode('result');
    }, 2000); 
  };

  const handleExportWord = () => {
    if (!resultData || !resultData.lessonPlan) return;
    const contentHtml = renderWordHTML(resultData.lessonPlan);
    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(contentHtml);
    const fileDownload = document.createElement("a");
    document.body.appendChild(fileDownload);
    fileDownload.href = source;
    fileDownload.download = `Giao_an_${formData.topic.replace(/\s+/g, '_')}.doc`;
    fileDownload.click();
    document.body.removeChild(fileDownload);
  };

  const handleTransformMethod = (actIndex: number, methodType: string) => {
      if(!resultData || !resultData.lessonPlan) return;
      const newData = { ...resultData };
      const act = newData.lessonPlan.activities[actIndex];
      act.name += ` [${methodType === 'gamification' ? 'Trò chơi hoá' : 'Lớp học đảo ngược'}]`;
      act.content += "\n(Nội dung đã được AI viết lại theo phương pháp mới...)";
      setResultData(newData);
  };

  const handleSectionElaborate = (sectionId: string, userPrompt: string) => {
      if (!resultData || resultData.mode !== 'creation') return;
      const newData = { ...resultData };
      if (sectionId === 'objectives') {
          newData.lessonPlan.objectives.knowledge.push(`(AI bổ sung chi tiết: ${userPrompt})`);
      } else if (sectionId.startsWith('activity_')) {
          const idx = parseInt(sectionId.split('_')[1]);
          if(newData.lessonPlan.activities[idx]) {
              newData.lessonPlan.activities[idx].content += `\n[AI viết thêm theo yêu cầu "${userPrompt}": Triển khai chi tiết phần này...]`;
          }
      }
      setResultData(newData);
  };

  const handleSidebarOptimize = (type: string) => {
      if (!resultData || !resultData.lessonPlan || !resultData.lessonPlan.activities) return;

      const newData = JSON.parse(JSON.stringify(resultData)); // Deep clone to avoid mutation

      // Prevent duplicate processing
      if (newData.lessonPlan.activities[0].content.includes("[NỘI DUNG CHI TIẾT BÁM SÁT SGK]")) {
          alert("Giáo án đã được tối ưu chi tiết theo SGK!");
          return;
      }

      if (type === 'detail_ai') {
          newData.lessonPlan.activities.forEach((act: Activity) => {
              // Expand general content with Textbook standard references
              act.content = `[NỘI DUNG CHI TIẾT BÁM SÁT SGK]\n` +
                            `1. Cơ sở kiến thức: Nội dung được xây dựng dựa trên chuẩn kiến thức kỹ năng và Sách Giáo Khoa (Bộ GD&ĐT).\n` +
                            `2. Chi tiết hoạt động:\n${act.content}\n` +
                            `3. Phân tích sư phạm: Giáo viên cần khai thác sâu các hình ảnh/dữ liệu trong SGK để học sinh tự kiến tạo tri thức. Chú ý các thuật ngữ khoa học chính xác.`;

              // Elaborate specifically on the 4 steps of 5512
              act.steps.forEach((step: Step) => {
                  if (step.stepName.toLowerCase().includes("chuyển giao")) {
                      step.teacherAction = `GV giao nhiệm vụ cụ thể: Yêu cầu HS đọc mục [...] trong SGK trang [...]. Kết hợp quan sát hình ảnh trực quan. GV kiểm tra lại xem HS đã nắm rõ nhiệm vụ chưa.`;
                  } else if (step.stepName.toLowerCase().includes("thực hiện")) {
                      step.teacherAction = `HS thực hiện nhiệm vụ cá nhân/nhóm. GV quan sát, gợi ý cho các nhóm gặp khó khăn (nhưng không làm thay). Lưu ý nhắc nhở HS bám sát ngữ liệu SGK.`;
                      step.output += " (HS ghi chép các ý chính vào vở/phiếu học tập).";
                  } else if (step.stepName.toLowerCase().includes("báo cáo")) {
                      step.teacherAction = `GV mời đại diện 1-2 nhóm trình bày. Yêu cầu các nhóm khác lắng nghe, nhận xét và phản biện. GV ghi lại các ý kiến (cả đúng và sai) lên bảng để thảo luận.`;
                  } else if (step.stepName.toLowerCase().includes("kết luận")) {
                      step.teacherAction = `GV chính xác hoá kiến thức. Phân tích bản chất vấn đề, chốt lại nội dung ghi bài theo chuẩn kiến thức kỹ năng. Giải quyết các sai lầm (nếu có) mà HS mắc phải.`;
                  }
              });
          });
          alert("Đã cập nhật nội dung giáo án chi tiết theo chuẩn SGK!");
      }

      setResultData(newData);
  };

  const handleAudit = () => {
      setAuditResult({
          score: 92,
          issues: [{type: 'success', msg: 'Mục tiêu phù hợp với yêu cầu cần đạt.'}]
      });
  };

  const handleAdminLogin = (success: boolean) => {
    if (success) {
      setIsAdminLoggedIn(true);
      setCurrentMode('admin_dashboard');
    }
  };

  const handleLogout = () => {
    setIsAdminLoggedIn(false);
    setCurrentMode('home');
  };

  // --- CONDITIONAL RENDERING ---

  if (currentMode === 'admin_login') {
    return <AdminLogin onLogin={handleAdminLogin} onBack={() => setCurrentMode('home')} />;
  }

  if (currentMode === 'admin_dashboard' && isAdminLoggedIn) {
    return <AdminDashboard onLogout={handleLogout} />;
  }

  // --- SUB-VIEWS FOR RIGHT PANEL ---
  const renderInputForm = () => (
      <div className="w-full max-w-2xl bg-white p-10 rounded-xl shadow-sm border border-gray-100 animate-fade-in mx-auto mt-10">
          <div className="flex items-center gap-4 mb-8 border-b border-gray-100 pb-6">
              <div className="p-3 rounded-xl bg-yellow-50 text-gold-accent">
                  {currentMode === 'create_input' ? <Edit3 size={28}/> : <RefreshCw size={28}/>}
              </div>
              <div>
                  <h2 className="text-2xl font-bold font-serif text-slate-800">{currentMode === 'create_input' ? 'Soạn bài mới' : 'Tích hợp năng lực số'}</h2>
                  <p className="text-slate-500 text-sm italic">Điền thông tin để AI hỗ trợ thầy cô tốt nhất.</p>
              </div>
          </div>

          <div className="space-y-6">
              <div className="grid grid-cols-2 gap-6">
                  <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Môn học</label>
                      <input type="text" className="w-full bg-white border border-gray-200 rounded-lg p-3 focus:outline-none focus:border-gold-accent focus:ring-1 focus:ring-gold-accent/20 transition-all" value={formData.subject} onChange={e => setFormData({...formData, subject: e.target.value})} />
                  </div>
                  <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Lớp</label>
                      <select className="w-full bg-white border border-gray-200 rounded-lg p-3 focus:outline-none focus:border-gold-accent focus:ring-1 focus:ring-gold-accent/20 transition-all" value={formData.grade} onChange={e => setFormData({...formData, grade: e.target.value})}>
                          {[6,7,8,9,10,11,12].map(g => <option key={g} value={g}>Lớp {g}</option>)}
                      </select>
                  </div>
              </div>

              <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Tên bài dạy / Chủ đề</label>
                  <input type="text" className="w-full bg-white border border-gray-200 rounded-lg p-3 focus:outline-none focus:border-gold-accent focus:ring-1 focus:ring-gold-accent/20 transition-all" value={formData.topic} onChange={e => setFormData({...formData, topic: e.target.value})} />
              </div>

              {currentMode === 'create_input' ? (
                  <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Mẫu giáo án</label>
                      <select className="w-full bg-white border border-gray-200 rounded-lg p-3 focus:outline-none focus:border-gold-accent focus:ring-1 focus:ring-gold-accent/20 transition-all" value={formData.template} onChange={e => setFormData({...formData, template: e.target.value})}>
                          {TEMPLATES.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                      </select>
                  </div>
              ) : (
                  <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Nội dung giáo án cũ</label>
                      <textarea className="w-full bg-white border border-gray-200 rounded-lg p-3 focus:outline-none focus:border-gold-accent focus:ring-1 focus:ring-gold-accent/20 transition-all min-h-[120px]" placeholder="Dán nội dung vào đây..." value={formData.originalText} onChange={e => setFormData({...formData, originalText: e.target.value})}></textarea>
                  </div>
              )}

              <div className="pt-6">
                  <button onClick={handleGenerate} className="w-full py-4 rounded-xl bg-gradient-to-br from-gold-accent to-gold-primary text-white shadow-lg hover:shadow-xl hover:brightness-110 active:translate-y-0.5 transition-all font-bold text-lg flex items-center justify-center gap-2 uppercase tracking-widest">
                      <Sparkles size={20} />
                      {currentMode === 'create_input' ? 'Khởi tạo bài giảng' : 'Phân tích & Tích hợp'}
                  </button>
              </div>
          </div>
      </div>
  );

  return (
    <div className="flex h-screen w-full bg-premium">

      {/* SIDEBAR */}
      <aside className="w-72 h-full flex flex-col bg-sidebar z-20 text-slate-300 shadow-xl border-r border-gold-accent/20">
        <div className="p-6 flex flex-col h-full">
            {/* Logo Area */}
            <div className="flex items-center gap-3 mb-10 cursor-pointer" onClick={() => setCurrentMode('home')}>
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-gold-accent to-gold-primary flex items-center justify-center shadow-lg">
                    <Wand2 className="text-white" size={20} />
                </div>
                <div className="flex flex-col">
                    <h1 className="text-white text-base font-bold leading-none tracking-tight">Thầy Trần Đông</h1>
                    <p className="text-gold-primary text-[10px] font-bold uppercase tracking-widest mt-1">AI Trainer Platform</p>
                </div>
            </div>

            {/* Navigation */}
            <nav className="flex flex-col gap-1 mb-8">
                <div onClick={() => setCurrentMode('create_input')} className={`flex items-center gap-3 px-3 py-2.5 rounded-lg cursor-pointer transition-all ${currentMode === 'create_input' ? 'bg-white/10 text-gold-accent border border-gold-accent/30' : 'hover:bg-white/5 hover:text-white'}`}>
