                <div className="flex items-center gap-3 px-3 py-2 text-slate-400 hover:text-white cursor-pointer transition-colors mt-2 border-t border-white/5 pt-4">
                    <div className="bg-slate-800 p-2 rounded-full"><User size={16} /></div>
                    <div>
                        <p className="text-xs font-bold text-white">GV. Nguyễn Văn A</p>
                        <p className="text-[10px]">Trường THPT Trần Phú</p>
