                          </select>
                      </div>
                  </div>

                  <div>
                      <label className="block text-xs font-bold text-slate-700 uppercase tracking-widest mb-2">Tên bài dạy / Chủ đề <span className="text-red-500">*</span></label>
                      <input 
                        type="text" 
