              {/* Upload & Suggestion Group */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* Textbook Upload */}
                  <div className="border border-dashed border-slate-300 rounded-xl p-5 hover:bg-slate-50 transition-colors relative">
                      <div className="flex items-center justify-between mb-3">
