                    <p className="text-sm text-slate-500 mt-2">Đang phân tích tài liệu và cấu trúc bài dạy</p>
                </div>
            )}

            {currentMode === 'result' && resultData && (
                <div className="max-w-[1000px] mx-auto pb-10">
                    {activeTab === 0 && <LessonPlan5512View data={resultData.lessonPlan} onTransform={handleTransformMethod} onElaborate={handleSectionElaborate} />}
                    {activeTab === 1 && <DigitalCompetencyView data={resultData.digitalPack} topic={formData.topic} />}
                    {activeTab === 2 && <WorksheetView data={resultData.worksheets} />}
                    {activeTab === 3 && <SlideView data={resultData.slides} />}
                </div>
            )}
        </div>
      </main>
    </div>
  );
};

export default App;

import { DIGITAL_COMPETENCY_DB } from '../constants';
import { FormData, LessonPlan, Worksheet, Slide, DigitalPack, AssessmentQuestion } from '../types';

export const generateDetailed5512Plan = (formData: FormData, isMath: boolean): LessonPlan => {
    const pickComp = (code: string) => DIGITAL_COMPETENCY_DB.find(c => c.code === code) || DIGITAL_COMPETENCY_DB[0];

    // Check if there is uploaded text/OCR content from AI Suggestion
    const hasOriginalText = formData.originalText && formData.originalText.length > 20;

    if (isMath) {
        return {
            topic: formData.topic || "Phương trình đường tròn",
            subject: formData.subject || "Toán học",
            grade: formData.grade || "10",
            duration: formData.duration || "2",
            objectives: {
                knowledge: [
                    "Phát biểu được định nghĩa đường tròn trong mặt phẳng tọa độ Oxy.",
                    "Thiết lập được phương trình đường tròn khi biết tọa độ tâm I(a; b) và bán kính R.",
                    "Nhận dạng được phương trình đường tròn ở dạng khai triển: x² + y² - 2ax - 2by + c = 0 và xác định được tâm, bán kính từ phương trình đó.",
                    "Vận dụng được kiến thức về phương trình đường tròn để giải quyết một số bài toán thực tế đơn giản."
                ],
