import WorksheetView from './components/WorksheetView';
import SlideView from './components/SlideView';
import DigitalCompetencyView from './components/DigitalCompetencyView';
import AdminDashboard from './components/AdminDashboard';
import AdminLogin from './components/AdminLogin';
import { TEMPLATES } from './constants';
import { generateDetailed5512Plan, generateMockWorksheets, generateMockSlides, generateMockDigitalPack, generateMockAssessment } from './utils/generators';
import { renderWordHTML } from './utils/export';
import { FormData, ResultData } from './types';

const App = () => {
  const [currentMode, setCurrentMode] = useState<string>('home'); 
  const [formData, setFormData] = useState<FormData>({
    grade: '10', subject: '', topic: '',
    duration: '1', template: 'toan_hinhhoc', classLevel: 'standard',
    integrationMode: 'inline', originalText: '', products: ['plan', 'questions'], selectedFramework: '3456_THCS',
    textbookFileName: '', frameworkFileName: ''
  });

  const [resultData, setResultData] = useState<ResultData | null>(null);
  const [activeTab, setActiveTab] = useState(0); 
  const [auditResult, setAuditResult] = useState<{score: number; issues: any[]} | null>(null);
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);

  // Refs for file inputs
  const textbookInputRef = useRef<HTMLInputElement>(null);
  const frameworkInputRef = useRef<HTMLInputElement>(null);

  // --- HANDLERS ---
  const handleGenerate = () => {
    // Validation
    if (!formData.subject.trim()) {
        alert("Vui lòng điền tên Môn học!");
        return;
    }
    if (!formData.grade) {
        alert("Vui lòng chọn Lớp học!");
        return;
    }
    if (!formData.topic.trim()) {
        alert("Vui lòng điền Tên bài dạy / Chủ đề!");
        return;
    }

    setCurrentMode('loading');
    setTimeout(() => {
      const isMath = formData.subject.toLowerCase().includes('toán') || formData.subject.toLowerCase().includes('hình');
      // Generator now strictly uses formData fields
      const lessonPlan = generateDetailed5512Plan(formData, isMath);

      setResultData({
        lessonPlan: lessonPlan,
        assessment: generateMockAssessment(formData, isMath),
        worksheets: generateMockWorksheets(formData, isMath),
        slides: generateMockSlides(formData),
        digitalPack: generateMockDigitalPack(formData),
        mode: formData.originalText ? 'integration' : 'creation'
      });
      setCurrentMode('result');
    }, 2500); 
  };

  const handleExportWord = () => {
    if (!resultData || !resultData.lessonPlan) return;
    const contentHtml = renderWordHTML(resultData.lessonPlan);
    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(contentHtml);
    const fileDownload = document.createElement("a");
    document.body.appendChild(fileDownload);
    fileDownload.href = source;
    fileDownload.download = `Giao_an_${formData.topic.replace(/\s+/g, '_')}.doc`;
    fileDownload.click();
    document.body.removeChild(fileDownload);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'textbook' | 'framework') => {
      if (e.target.files && e.target.files.length > 0) {
          const fileName = e.target.files[0].name;
          if (type === 'textbook') {
             // Mock OCR/Reading file based on user input topic
              const simulatedContent = `[DỮ LIỆU TỪ FILE: ${fileName}]\n\nCHƯƠNG TRÌNH: ${formData.subject.toUpperCase()} ${formData.grade}\nBÀI HỌC: ${formData.topic.toUpperCase()}\n\n1. KIẾN THỨC TRỌNG TÂM:\n- Khái niệm cơ bản về ${formData.topic}...\n- Các định lý/tính chất quan trọng của ${formData.topic}...\n\n2. KỸ NĂNG CẦN ĐẠT:\n- Vận dụng kiến thức ${formData.topic} vào giải quyết vấn đề thực tiễn.\n\n(Nguồn: Sách giáo khoa Kết Nối Tri Thức)`;

              setFormData(prev => ({
                  ...prev, 
                  textbookFileName: fileName, 
                  originalText: simulatedContent
              }));
          } else {
              setFormData({...formData, frameworkFileName: fileName});
          }
      }
  };

  const handleAiSuggest = () => {
      if (!formData.topic || !formData.subject) {
          alert("Vui lòng nhập Môn học và Tên bài dạy trước để AI gợi ý nội dung!");
          return;
      }
      setIsSuggesting(true);

      const isMath = formData.subject.toLowerCase().includes('toán') || formData.subject.toLowerCase().includes('hình');

      setTimeout(() => {
          let aiContent = "";

          if (isMath && formData.topic.toLowerCase().includes("hình bình hành")) {
              aiContent = `[AI GỢI Ý - CHUẨN KẾT NỐI TRI THỨC]\n\nI. KIẾN THỨC CẦN NHỚ\n1. Định nghĩa: Hình bình hành là tứ giác có các cạnh đối song song.\n   ABCD là hình bình hành <=> AB // CD và AD // BC.\n\n2. Tính chất:\n   - Các cạnh đối bằng nhau: AB = CD; AD = BC.\n   - Các góc đối bằng nhau: ∠A = ∠C; ∠B = ∠D.\n   - Hai đường chéo cắt nhau tại trung điểm mỗi đường: OA = OC; OB = OD.\n\n3. Dấu hiệu nhận biết:\n   - Tứ giác có các cạnh đối song song.\n   - Tứ giác có các cạnh đối bằng nhau.\n   - Tứ giác có hai cạnh đối song song và bằng nhau.\n   - Tứ giác có các góc đối bằng nhau.\n   - Tứ giác có hai đường chéo cắt nhau tại trung điểm mỗi đường.`;
          } else if (isMath) {
              aiContent = `[AI GỢI Ý - CHUẨN KẾT NỐI TRI THỨC]\n\nBÀI: ${formData.topic.toUpperCase()}\n\n1. Lý thuyết trọng tâm:\n- Định nghĩa và các khái niệm cơ bản về ${formData.topic}.\n- Các công thức tính toán cần nhớ.\n\n2. Các dạng bài tập thường gặp:\n- Dạng 1: Nhận biết ${formData.topic}.\n- Dạng 2: Tính toán các thông số.\n- Dạng 3: Bài toán chứng minh.\n\n(Nội dung chuẩn hóa theo SGK Toán ${formData.grade})`;
          } else {
              aiContent = `[AI GỢI Ý - CHUẨN KẾT NỐI TRI THỨC]\n\nBÀI: ${formData.topic.toUpperCase()}\nMÔN: ${formData.subject.toUpperCase()} - LỚP ${formData.grade}\n\nI. YÊU CẦU CẦN ĐẠT:\n- Nêu được khái niệm về ${formData.topic}.\n- Giải thích được ý nghĩa thực tiễn của ${formData.topic}.\n\nII. NỘI DUNG CHI TIẾT:\n1. Định nghĩa: ${formData.topic} là...\n2. Đặc điểm chính: ...\n3. Ứng dụng: ...\n\n(Nội dung được trích xuất chuẩn theo chương trình GDPT 2018)`;
          }

          setFormData(prev => ({
              ...prev, 
              originalText: aiContent
          }));
          setIsSuggesting(false);
      }, 1500);
  };

  const handleAudit = () => {
      setAuditResult({
          score: 98,
          issues: [{type: 'success', msg: 'Cấu trúc bài dạy rất chi tiết và đúng quy định 5512.'}]
      });
  };

  const handleAdminLogin = (success: boolean) => {
    if (success) {
      setIsAdminLoggedIn(true);
      setCurrentMode('admin_dashboard');
    }
  };

  const handleLogout = () => {
    setIsAdminLoggedIn(false);
    setCurrentMode('home');
  };

  // Unused handlers removed as requested to clean up the UI logic
  const handleTransformMethod = (actIndex: number, methodType: string) => {};
  const handleSectionElaborate = (sectionId: string, userPrompt: string) => {};


  // --- CONDITIONAL RENDERING ---

  if (currentMode === 'admin_login') {
    return <AdminLogin onLogin={handleAdminLogin} onBack={() => setCurrentMode('home')} />;
  }

  if (currentMode === 'admin_dashboard' && isAdminLoggedIn) {
    return <AdminDashboard onLogout={handleLogout} />;
  }

  // --- SUB-VIEWS FOR RIGHT PANEL ---
  const renderInputForm = () => (
      <div className="w-full max-w-3xl bg-white p-10 rounded-xl shadow-sm border border-gray-100 animate-fade-in mx-auto mt-6 mb-10">
          <div className="flex items-center gap-4 mb-8 border-b border-gray-100 pb-6">
              <div className="p-3 rounded-xl bg-yellow-50 text-gold-accent">
                  <Edit3 size={28}/>
              </div>
              <div>
                  <h2 className="text-2xl font-bold font-serif text-slate-800">Soạn bài mới</h2>
                  <p className="text-slate-500 text-sm italic">Điền thông tin và tải tài liệu để AI khởi tạo bài giảng chi tiết.</p>
              </div>
          </div>

          <div className="space-y-6">
              {/* Mandatory Fields Group */}
              <div className="bg-slate-50 p-6 rounded-lg border border-slate-100">
