import React, { useRef, useEffect } from 'react';
import katex from 'katex';

interface Props {
  content: string;
}

const ContentRenderer: React.FC<Props> = ({ content }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (containerRef.current && content) {
      // Logic để parse text và render Math (dạng $...$ hoặc $$...$$)
      // Đây là một parser đơn giản. Trong thực tế có thể dùng thư viện markdown-it-katex hoặc tương tự.
      const renderMath = (text: string) => {
        const parts = text.split(/(\$\$[\s\S]*?\$\$|\$[\s\S]*?\$)/g);
        return parts.map((part, index) => {
          if (part.startsWith('$$') && part.endsWith('$$')) {
            // Block math
            const formula = part.slice(2, -2);
            try {
              return katex.renderToString(formula, { displayMode: true, throwOnError: false });
            } catch (e) {
              return part;
            }
          } else if (part.startsWith('$') && part.endsWith('$')) {
            // Inline math
            const formula = part.slice(1, -1);
            try {
              return katex.renderToString(formula, { displayMode: false, throwOnError: false });
            } catch (e) {
              return part;
            }
          } else {
             // Xử lý xuống dòng cho text thường
             return part.replace(/\n/g, '<br/>');
          }
        }).join('');
      };

      // Nếu content chứa SVG tag, render trực tiếp
      if (content.trim().startsWith('<svg')) {
          containerRef.current.innerHTML = content;
      } else {
          // Render Math + Text
          containerRef.current.innerHTML = renderMath(content);
      }
    }
  }, [content]);

  if (!content) return null;

  return <div ref={containerRef} className="content-renderer"></div>;
};

export default ContentRenderer;

