interface Props {
  onLogin: (success: boolean) => void;
  onBack: () => void;
}

const AdminLogin: React.FC<Props> = ({ onLogin, onBack }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const { data, error } = await supabase.auth.signInWithPassword({
        email: email,
        password: password,
      });

      if (error) throw error;

      if (data.user) {
        onLogin(true);
      }
    } catch (err: any) {
      setError(err.message || 'Đăng nhập thất bại. Vui lòng kiểm tra lại.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background-light relative overflow-hidden font-sans">
      <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-trainer-gold/5 rounded-full blur-[120px] -z-10 translate-x-1/2 -translate-y-1/2"></div>
      <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-trainer-gold-dark/5 rounded-full blur-[100px] -z-10 -translate-x-1/2 translate-y-1/2"></div>

      <div className="w-full max-w-md p-8 glass-card rounded-3xl shadow-2xl animate-fade-in relative z-10">
        <div className="text-center mb-10">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-trainer-gold/10 mb-4">
                <span className="material-symbols-outlined text-trainer-gold text-4xl">shield_lock</span>
            </div>
            <h2 className="text-2xl font-bold text-slate-900">Quản trị Hệ thống</h2>
            <p className="text-slate-500 text-sm mt-2">Đăng nhập qua Supabase Auth</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Email</label>
            <div className="relative">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"><User size={18} /></span>
              <input 
                type="email" 
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-trainer-gold focus:ring-1 focus:ring-trainer-gold/50 transition-all text-sm"
                placeholder="admin@example.com"
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Mật khẩu</label>
            <div className="relative">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"><Lock size={18} /></span>
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-trainer-gold focus:ring-1 focus:ring-trainer-gold/50 transition-all text-sm"
                placeholder="••••••••"
                required
              />
            </div>
          </div>

          {error && (
            <div className="text-red-500 text-xs font-medium text-center bg-red-50 py-2 rounded-lg">
              {error}
            </div>
          )}

          <div className="pt-2">
            <button type="submit" disabled={loading} className="w-full gold-button-gradient text-white py-3.5 rounded-xl font-bold shadow-lg shadow-trainer-gold/20 hover:opacity-90 active:scale-95 transition-all uppercase tracking-wide text-sm flex items-center justify-center gap-2">
              {loading && <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>}
              {loading ? 'Đang xác thực...' : 'Đăng nhập'}
            </button>
          </div>
        </form>

        <div className="mt-8 text-center">
            <button onClick={onBack} className="text-slate-400 hover:text-trainer-gold text-sm font-medium transition-colors flex items-center justify-center gap-2 mx-auto">
                <span className="material-symbols-outlined text-lg">arrow_back</span> Quay lại trang chủ
            </button>
        </div>
      </div>
    </div>
  );
};

