    totalViews: 0, // Mock data
    totalUsers: 1, // Mock data
    recentGrowth: 0
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      // Fetch Lesson Plans
      const { data, error } = await supabase
        .from('lesson_plans')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;

      if (data) {
        setPlans(data as LessonPlanRecord[]);
        setStats(prev => ({
          ...prev,
          totalPlans: data.length,
          recentGrowth: data.filter(p => {
             const date = new Date(p.created_at);
             const now = new Date();
             const diffTime = Math.abs(now.getTime() - date.getTime());
             const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
             return diffDays <= 7;
          }).length
        }));
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
