const AdminDashboard: React.FC<Props> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<Tab>('dashboard');
  const [plans, setPlans] = useState<LessonPlanRecord[]>([]);
  const [files, setFiles] = useState<StorageFile[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedPlan, setSelectedPlan] = useState<LessonPlanRecord | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [uploading, setUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Stats
  const [stats, setStats] = useState({
    totalPlans: 0,
    totalFiles: 0,
    totalUsers: 1, 
    recentGrowth: 0
  });

  useEffect(() => {
    fetchData();
  }, []);

  useEffect(() => {
    if (activeTab === 'documents') {
        fetchDocuments();
    }
  }, [activeTab]);

  const fetchData = async () => {
    setLoading(true);
    try {
      // Fetch Lesson Plans
      const { data: plansData, error: plansError } = await supabase
        .from('lesson_plans')
        .select('*')
        .order('created_at', { ascending: false });

      if (plansError) throw plansError;

      // Fetch File Count (mock or real if bucket exists)
      const { data: filesData } = await supabase.storage.from('documents').list();

      if (plansData) {
        setPlans(plansData as LessonPlanRecord[]);
        setStats(prev => ({
          ...prev,
          totalPlans: plansData.length,
          totalFiles: filesData ? filesData.length : 0,
          recentGrowth: plansData.filter(p => {
             const date = new Date(p.created_at);
             const now = new Date();
             const diffTime = Math.abs(now.getTime() - date.getTime());
             const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
             return diffDays <= 7;
          }).length
        }));
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchDocuments = async () => {
      setLoading(true);
      try {
          const { data, error } = await supabase.storage.from('documents').list(undefined, {
              limit: 100,
              offset: 0,
              sortBy: { column: 'created_at', order: 'desc' },
          });
          if (error) throw error;
          if (data) setFiles(data as unknown as StorageFile[]);
      } catch (error: any) {
          console.error("Error fetching documents:", error);
          // Don't alert if bucket doesn't exist, just show empty
      } finally {
          setLoading(false);
      }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (!e.target.files || e.target.files.length === 0) return;

      setUploading(true);
      const file = e.target.files[0];
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}_${file.name.replace(/[^a-zA-Z0-9]/g, '_')}.${fileExt}`;

      try {
          const { error } = await supabase.storage.from('documents').upload(fileName, file);
          if (error) throw error;

          alert('Tải lên thành công!');
          fetchDocuments(); // Refresh list
      } catch (error: any) {
          console.error('Upload error:', error);
          alert(`Lỗi tải file: ${error.message}`);
      } finally {
          setUploading(false);
          if (fileInputRef.current) fileInputRef.current.value = '';
      }
  };

  const handleDeleteFile = async (fileName: string) => {
      if (!window.confirm(`Bạn chắc chắn muốn xóa file ${fileName}?`)) return;

      try {
          const { error } = await supabase.storage.from('documents').remove([fileName]);
          if (error) throw error;

          setFiles(files.filter(f => f.name !== fileName));
          setStats(prev => ({ ...prev, totalFiles: prev.totalFiles - 1 }));
      } catch (error: any) {
          alert(`Lỗi xóa file: ${error.message}`);
      }
  };

  const getFileUrl = (fileName: string) => {
      const { data } = supabase.storage.from('documents').getPublicUrl(fileName);
      return data.publicUrl;
  };

  const formatFileSize = (bytes: number) => {
      if (bytes === 0) return '0 Bytes';
      const k = 1024;
      const sizes = ['Bytes', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const handleDeletePlan = async (id: number) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa giáo án này không?')) {
      try {
        const { error } = await supabase.from('lesson_plans').delete().eq('id', id);
        if (error) throw error;
        setPlans(plans.filter(p => p.id !== id));
        setStats(prev => ({...prev, totalPlans: prev.totalPlans - 1}));
      } catch (error) {
        alert('Lỗi khi xóa giáo án');
        console.error(error);
      }
